import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => {
  if (!process.env.API_KEY) {
    throw new Error("API Key not found in environment.");
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const chatWithPMTwin = async (messages: { role: string; content: string }[]) => {
  const ai = getAI();
  const history = messages.slice(0, -1).map(m => ({
    role: m.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: m.content }]
  }));

  const lastMessage = messages[messages.length - 1].content;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        ...history.map(h => ({ role: h.role, parts: h.parts })),
        { role: 'user', parts: [{ text: lastMessage }] }
      ],
      config: {
        systemInstruction: `You are the "AI Digital Twin" of a world-class Senior Product Manager. 
        Your creator's name is "The Strategist". 
        Expertise: Product Strategy, UI/UX Design, and Prompt Engineering.
        Tone: Professional, insightful, minimalist, and slightly visionary.
        Goal: Answer questions about your creator's work, methodology, and the projects listed in the portfolio.
        Context: The portfolio includes projects like Nexus AI (modular workspace), Pulse Design System, and FinStream.
        Keep responses concise and impactful. If asked about salary or personal details, deflect politely to professional topics.`,
        temperature: 0.7,
        topP: 0.9,
      },
    });

    return response.text || "I'm contemplating that. Could you rephrase?";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I seem to be experiencing a momentary disconnect. Let's try again.";
  }
};

export const getPromptFeedback = async (prompt: string) => {
  const ai = getAI();
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ text: `Act as a Prompt Engineering Expert. Review this prompt and provide 3 specific tips for optimization: "${prompt}"` }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            score: { type: Type.NUMBER, description: "Prompt clarity score 1-10" },
            critique: { type: Type.STRING },
            suggestions: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["score", "critique", "suggestions"]
        }
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Feedback Error:", error);
    return null;
  }
};

